#!/bin/bash # HALT Windows Package Validation Script (Bash version) # Validates the package structure and installation components set -e # Colors for output RED='\033[0;31m' GREEN='\033[0;32m' YELLOW='\033[1;33m' BLUE='\033[0;34m' CYAN='\033[0;36m' NC='\033[0m' # No Color # Validation Configuration PACKAGE_PATH="windows_package" VALIDATION_CONFIG=" installer/halt.wxs service/halt-service.xml service/Manage-HaltService.ps1 service/prestart.ps1 service/prestop.ps1 scripts/Docker-Halt.ps1 scripts/Build-Halt.exe.ps1 scripts/install-halt.bat scripts/Validate-WindowsPackage.ps1 docs/Windows-Installation-Guide.md " OPTIONAL_FILES=" images/halt-icon.ico images/halt-logo.png " REQUIRED_DIRS=" installer service scripts docs images " print_usage() { echo -e "${CYAN}HALT Windows Package Validation Script${NC}" echo "" echo "Usage: $0 [ACTION]" echo "" echo "Actions:" echo " validate - Validate package structure and files" echo " package - Create distribution package" echo " check - Basic file structure check" echo " help - Show this help message" echo "" echo "Examples:" echo " $0 validate" echo " $0 package" echo " $0 check" } print_validation_result() { local message="$1" local type="$2" case "$type" in "success") echo -e "${GREEN}[OK] $message${NC}" ;; "error") echo -e "${RED}[FAIL] $message${NC}" ;; "warning") echo -e "${YELLOW}[EMOJI] $message${NC}" ;; "info") echo -e "${BLUE}Info: $message${NC}" ;; *) echo "$message" ;; esac } validate_directory_structure() { echo -e "${BLUE}Validating directory structure...${NC}" local errors=0 # Check required directories for dir in $REQUIRED_DIRS; do if [ -d "$PACKAGE_PATH/$dir" ]; then print_validation_result "Directory found: $dir" "success" else print_validation_result "Directory missing: $dir" "error" ((errors++)) fi done return $errors } validate_required_files() { echo -e "${BLUE}Validating required files...${NC}" local errors=0 local warnings=0 # Check required files while IFS= read -r file; do if [ -f "$PACKAGE_PATH/$file" ]; then # Check if file has content if [ -s "$PACKAGE_PATH/$file" ]; then print_validation_result "File valid: $file" "success" else print_validation_result "File empty: $file" "warning" ((warnings++)) fi else print_validation_result "File missing: $file" "error" ((errors++)) fi done <<< "$VALIDATION_CONFIG" return $((errors + warnings * 100)) } validate_optional_files() { echo -e "${BLUE}Validating optional files...${NC}" while IFS= read -r file; do if [ -f "$PACKAGE_PATH/$file" ]; then print_validation_result "Optional file found: $file" "info" else print_validation_result "Optional file missing: $file" "warning" fi done <<< "$OPTIONAL_FILES" } validate_powershell_syntax() { echo -e "${BLUE}Validating PowerShell script syntax...${NC}" local errors=0 # Find all .ps1 files while IFS= read -r psfile; do if [[ $psfile == *.ps1 ]]; then # Basic syntax check by looking for common issues if grep -q "Set-StrictMode -Version" "$psfile" 2>/dev/null || \ grep -q "^#.*PowerShell.*Script" "$psfile" 2>/dev/null || \ grep -q "^param(" "$psfile" 2>/dev/null; then print_validation_result "PowerShell script looks valid: $(basename "$psfile")" "success" else # Check if it has basic PowerShell structure if grep -q "function\|param\|\$PSScriptRoot" "$psfile" 2>/dev/null; then print_validation_result "PowerShell script structure OK: $(basename "$psfile")" "success" else print_validation_result "PowerShell script may have issues: $(basename "$psfile")" "warning" fi fi fi done < <(find "$PACKAGE_PATH" -name "*.ps1" -type f) return $errors } validate_batch_files() { echo -e "${BLUE}Validating batch file structure...${NC}" local errors=0 # Find all .bat files while IFS= read -r batfile; do if [ -s "$batfile" ]; then # Check for basic batch file structure if grep -q "@echo off\|echo\|set\|if\|for" "$batfile" 2>/dev/null; then print_validation_result "Batch file structure OK: $(basename "$batfile")" "success" else print_validation_result "Batch file may be incomplete: $(basename "$batfile")" "warning" ((errors++)) fi else print_validation_result "Batch file empty: $(basename "$batfile")" "warning" ((errors++)) fi done < <(find "$PACKAGE_PATH" -name "*.bat" -type f) return $errors } validate_wix_configuration() { echo -e "${BLUE}Validating WiX configuration...${NC}" local wix_file="$PACKAGE_PATH/installer/halt.wxs" if [ ! -f "$wix_file" ]; then print_validation_result "WiX configuration file not found" "error" return 1 fi # Basic XML structure validation if grep -q "<?xml" "$wix_file" && \ grep -q "<Wix" "$wix_file" && \ grep -q "<Product" "$wix_file"; then print_validation_result "WiX XML structure looks valid" "success" else print_validation_result "WiX XML may have structural issues" "warning" return 1 fi # Check for required elements local required_elements=("Product" "Package" "Directory" "Component" "Feature") for element in "${required_elements[@]}"; do if grep -q "<$element" "$wix_file"; then print_validation_result "WiX element found: $element" "success" else print_validation_result "WiX element missing: $element" "warning" fi done return 0 } validate_docker_config() { echo -e "${BLUE}Validating Docker configuration...${NC}" # Check main docker-compose files local docker_files=("../docker-compose.yml" "../docker-compose.prod.yml") for docker_file in "${docker_files[@]}"; do local full_path="$PACKAGE_PATH/$docker_file" if [ -f "$full_path" ]; then # Basic YAML validation if grep -q "version:" "$full_path" && grep -q "services:" "$full_path"; then print_validation_result "Docker compose file looks valid: $(basename "$docker_file")" "success" else print_validation_result "Docker compose file may have issues: $(basename "$docker_file")" "warning" fi fi done } create_distribution_package() { echo -e "${BLUE}Creating distribution package...${NC}" local timestamp=$(date +"%Y%m%d_%H%M%S") local package_name="HALT-Windows-Package-$timestamp" local dist_dir="../dist" local package_dir="$dist_dir/$package_name" # Create distribution directory mkdir -p "$dist_dir" # Remove existing package if it exists if [ -d "$package_dir" ]; then rm -rf "$package_dir" fi mkdir -p "$package_dir" # Copy all package files print_validation_result "Copying package files..." "info" cp -r "$PACKAGE_PATH"/* "$package_dir/" # Copy main application files local main_files=( "../Dockerfile" "../docker-compose.yml" "../docker-compose.prod.yml" "../package.json" "../Makefile" "../README.md" ) for file in "${main_files[@]}"; do if [ -f "../$file" ]; then cp "../$file" "$package_dir/" print_validation_result "Copied: $(basename "$file")" "success" fi done # Create README for the package cat > "$package_dir/README.txt" << EOF # HALT Windows Package This package contains all the necessary files for installing HALT on Windows. ## Package Contents - installer/: WiX MSI installer configuration - service/: Windows service management scripts - scripts/: Installation and management scripts - docs/: Installation guide and documentation ## Quick Installation 1. Run scripts\\install-halt.bat as Administrator for automated installation 2. Or use scripts\\Docker-Halt.ps1 for Docker-based installation 3. Or use service\\Manage-HaltService.ps1 for service-only installation ## Documentation See docs\\Windows-Installation-Guide.md for detailed installation instructions. ## System Requirements - Windows 10/11 (64-bit) - 4 GB RAM minimum, 8 GB recommended - 2 GB free storage space For more information: https://docs.halt.com --- Generated: $(date) EOF # Create ZIP archive local zip_path="$dist_dir/$package_name.zip" if command -v zip >/dev/null 2>&1; then cd "$dist_dir" zip -r "$package_name.zip" "$package_name/" >/dev/null 2>&1 cd - >/dev/null local zip_size=$(du -h "$zip_path" | cut -f1) print_validation_result "ZIP archive created: $zip_path ($zip_size)" "success" else print_validation_result "ZIP utility not available, skipping archive creation" "warning" fi # Calculate package size local package_size=$(du -sh "$package_dir" | cut -f1) print_validation_result "Distribution package created successfully" "success" print_validation_result "Package location: $package_dir" "info" print_validation_result "Package size: $package_size" "info" echo "" echo -e "${CYAN}Distribution package created: $package_dir${NC}" } basic_structure_check() { echo -e "${BLUE}Performing basic structure check...${NC}" local file_count=$(find "$PACKAGE_PATH" -type f | wc -l) local dir_count=$(find "$PACKAGE_PATH" -type d | wc -l) echo -e "${GREEN}Package structure overview:${NC}" echo " Files: $file_count" echo " Directories: $dir_count" echo "" # List main directories echo -e "${CYAN}Main directories:${NC}" for dir in $REQUIRED_DIRS; do if [ -d "$PACKAGE_PATH/$dir" ]; then local file_count_dir=$(find "$PACKAGE_PATH/$dir" -type f | wc -l) echo " $dir: $file_count_dir files" fi done } # Main execution case "${1:-validate}" in "validate") echo -e "${CYAN}========================================${NC}" echo -e "${CYAN} HALT Windows Package Validation${NC}" echo -e "${CYAN}========================================${NC}" echo "" local total_errors=0 local total_warnings=0 # Run all validations validate_directory_structure total_errors=$((total_errors + $?)) validate_required_files local result=$? if [ $result -ge 100 ]; then total_warnings=$((total_warnings + (result / 100))) total_errors=$((total_errors + (result % 100))) else total_errors=$((total_errors + result)) fi validate_optional_files validate_powershell_syntax validate_batch_files validate_wix_configuration validate_docker_config # Summary echo "" echo -e "${BLUE}Validation Summary:${NC}" print_validation_result "Errors: $total_errors" "$(if [ $total_errors -eq 0 ]; then echo "success"; else echo "error"; fi)" print_validation_result "Warnings: $total_warnings" "$(if [ $total_warnings -eq 0 ]; then echo "success"; else echo "warning"; fi)" echo "" if [ $total_errors -eq 0 ]; then echo -e "${GREEN}[EMOJI] Package validation PASSED!${NC}" exit 0 else echo -e "${YELLOW}[EMOJI][EMOJI] Package validation completed with issues${NC}" exit 1 fi ;; "package") create_distribution_package ;; "check") basic_structure_check ;; "help"|"-h"|"--help") print_usage ;; *) echo -e "${RED}Unknown action: $1${NC}" print_usage exit 1 ;; esac